  board: number[][] = [];
  score = 0;
  moves = 0;
  state: '"'running' | 'won' | 'lost' = 'running';
  rngState = 1;
  scheduler = new Scheduler();

  constructor() {
    this.reset();
  }

  reset() {
    this.board = Array.from({length:4}, () => Array.from({length:4}, () => 0));
    this.score = 0;
    this.moves = 0;
    this.state = 'running';
    // deterministic default seed
    this.rngState = 123456;
    // spawn two tiles
    this.spawnRandomTile();
    this.spawnRandomTile();
